import React, { useState, useCallback, useEffect } from 'react';
import { GameStage, Player, BoardActivities, SnakeOrLadder, ActivityType, VisualSettings } from '../types';
import { BOARD_SIZE } from '../constants';
import { SetupScreen } from './SetupScreen';
import { GameBoard } from './GameBoard';
import { GameControls } from './GameControls';
import { ActivityModal } from './ActivityModal';
import { VictoryScreen } from './VictoryScreen';

const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

interface SnakeLadderGameProps {
  visualSettings: VisualSettings;
  onBackToMenu: () => void;
}

export const SnakeLadderGame: React.FC<SnakeLadderGameProps> = ({ visualSettings, onBackToMenu }) => {
  // Internal stage for this specific game (Setup -> Playing -> Finished)
  const [internalStage, setInternalStage] = useState<GameStage>(GameStage.Setup);

  const [players, setPlayers] = useState<Player[]>([]);
  const [activities, setActivities] = useState<BoardActivities>({});
  const [snakes, setSnakes] = useState<SnakeOrLadder[]>([]);
  const [ladders, setLadders] = useState<SnakeOrLadder[]>([]);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0);
  const [diceResult, setDiceResult] = useState(1);
  const [isRolling, setIsRolling] = useState(false);
  const [activeActivity, setActiveActivity] = useState<{ square: number; content: string } | null>(null);
  const [winner, setWinner] = useState<Player | null>(null);
  const [canRoll, setCanRoll] = useState(true);

  // New states for cognitive mode
  const [activityType, setActivityType] = useState<ActivityType>('psychomotor');
  const [pendingQuestions, setPendingQuestions] = useState<Record<number, string | null>>({});

  useEffect(() => {
    if (internalStage === GameStage.Playing || internalStage === GameStage.Finished) {
      document.body.classList.add('game-active');
    } else {
      document.body.classList.remove('game-active');
    }
    return () => {
      document.body.classList.remove('game-active');
    };
  }, [internalStage]);

  const handleStartGame = useCallback((
    newPlayers: Player[],
    newActivities: BoardActivities,
    newSnakes: SnakeOrLadder[],
    newLadders: SnakeOrLadder[],
    newActivityType: ActivityType,
  ) => {
    setPlayers(newPlayers);
    setActivities(newActivities);
    setSnakes(newSnakes);
    setLadders(newLadders);
    setActivityType(newActivityType);
    setCurrentPlayerIndex(0);
    setDiceResult(1);
    setIsRolling(false);
    setActiveActivity(null);
    setWinner(null);
    setCanRoll(true);
    setPendingQuestions({});
    setInternalStage(GameStage.Playing);
  }, []);

  const handleResetGame = useCallback(() => {
    setInternalStage(GameStage.Setup);
  }, []);

  // Reset internal state but stay in Setup mode or go back via prop
  const handleNewGame = useCallback(() => {
     // If user wants to "Go Home" from victory screen, we use the parent prop
     onBackToMenu();
  }, [onBackToMenu]);

  const movePlayerAlongPath = async (path: number[], playerIndex: number) => {
    for (const position of path) {
      setPlayers(currentPlayers => {
          const newPlayers = [...currentPlayers];
          if (newPlayers[playerIndex]) {
              newPlayers[playerIndex] = { ...newPlayers[playerIndex], position };
          }
          return newPlayers;
      });
      await delay(300); 
    }
  };

  const handleRollDice = useCallback(async () => {
    if (!canRoll || isRolling) return;

    setCanRoll(false);
    setIsRolling(true);
    const roll = Math.floor(Math.random() * 6) + 1;
    setDiceResult(roll);

    await delay(700);
    setIsRolling(false);

    const currentPlayer = players[currentPlayerIndex];
    const startPosition = currentPlayer.position;
    const tempPosition = startPosition + roll;

    const path: number[] = [];
    let landPosition: number;

    if (tempPosition > BOARD_SIZE) {
        landPosition = BOARD_SIZE - (tempPosition - BOARD_SIZE);
        for (let i = startPosition + 1; i <= BOARD_SIZE; i++) {
            path.push(i);
        }
        for (let i = BOARD_SIZE - 1; i >= landPosition; i--) {
            path.push(i);
        }
    } else {
        landPosition = tempPosition;
        for (let i = startPosition + 1; i <= landPosition; i++) {
            path.push(i);
        }
    }

    if (path.length > 0) {
        await movePlayerAlongPath(path, currentPlayerIndex);
    }

    if (landPosition === BOARD_SIZE) {
        await delay(500);
        setWinner(players[currentPlayerIndex]);
        setInternalStage(GameStage.Finished);
        return;
    }

    let finalPosition = landPosition;
    const ladder = ladders.find(l => l.start === landPosition);
    const snake = snakes.find(s => s.start === landPosition);

    if (ladder) {
        finalPosition = ladder.end;
    } else if (snake) {
        finalPosition = snake.end;
    }

    if (finalPosition !== landPosition) {
        await delay(200);
        setPlayers(currentPlayers => {
            const newPlayers = [...currentPlayers];
            if (newPlayers[currentPlayerIndex]) {
                newPlayers[currentPlayerIndex].position = finalPosition;
            }
            return newPlayers;
        });
        await delay(1000);
    }

    // --- Activity & Turn Logic ---
    const activityContent = activities[finalPosition];
    if (activityContent) {
        setActiveActivity({ square: finalPosition, content: activityContent });
        if (activityType === 'cognitive') {
            setPendingQuestions(prev => ({ ...prev, [currentPlayer.id]: activityContent }));
        }
    }

    // --- Turn Progression Logic ---
    if (activityType === 'cognitive') {
        setCurrentPlayerIndex((prevIndex) => (prevIndex + 1) % players.length);
        setCanRoll(true);
    } else { 
        if (!activityContent) {
            setCurrentPlayerIndex((prevIndex) => (prevIndex + 1) % players.length);
            setCanRoll(true);
        }
    }

  }, [canRoll, isRolling, players, currentPlayerIndex, activities, ladders, snakes, activityType]);

  const handleCloseModal = () => {
    setActiveActivity(null);
    if (activityType === 'psychomotor') {
        setCurrentPlayerIndex((prevIndex) => (prevIndex + 1) % players.length);
        setCanRoll(true);
    }
  };

  const handleAnswerCorrect = useCallback(() => {
    const currentPlayer = players[currentPlayerIndex];
    if (!currentPlayer) return;
    setPendingQuestions(prev => ({ ...prev, [currentPlayer.id]: null }));
    setCanRoll(true);
  }, [players, currentPlayerIndex]);

  const handleAnswerIncorrect = useCallback(() => {
    setCurrentPlayerIndex((prevIndex) => (prevIndex + 1) % players.length);
    setCanRoll(true); 
  }, [players.length]);


  // RENDER LOGIC BASED ON INTERNAL STAGE

  if (internalStage === GameStage.Setup) {
    return <SetupScreen onStartGame={handleStartGame} visualSettings={visualSettings} onBack={onBackToMenu} />;
  }

  if (internalStage === GameStage.Finished && winner) {
    return (
      <VictoryScreen 
        winner={winner}
        onNewGame={handleNewGame} // This goes back to menu
        onResetGame={handleResetGame} // This goes back to setup
      />
    );
  }

  // Playing Stage
  const currentPlayer = players.length > 0 ? players[currentPlayerIndex] : null;
  const pendingQuestion = currentPlayer ? pendingQuestions[currentPlayer.id] : null;

  return (
    <div className="min-h-screen flex flex-col md:flex-row items-center md:items-start justify-center p-4 sm:p-6 lg:p-8 gap-6 md:gap-8">
      <main className="w-full flex-grow">
        <GameBoard
          players={players}
          snakes={snakes}
          ladders={ladders}
          currentPlayerId={currentPlayer?.id ?? -1}
          visualSettings={visualSettings}
        />
      </main>
      <aside className="w-full md:w-80 lg:w-96 flex-shrink-0">
        {currentPlayer && (
          <GameControls
            players={players}
            currentPlayer={currentPlayer}
            onRollDice={handleRollDice}
            onReset={handleResetGame}
            onGoHome={onBackToMenu}
            diceResult={diceResult}
            isRolling={isRolling}
            canRoll={canRoll}
            activityType={activityType}
            pendingQuestion={pendingQuestion}
            onAnswerCorrect={handleAnswerCorrect}
            onAnswerIncorrect={handleAnswerIncorrect}
          />
        )}
      </aside>
      {activeActivity && (
        <ActivityModal
          activity={activeActivity.content}
          squareNumber={activeActivity.square}
          onClose={handleCloseModal}
        />
      )}
    </div>
  );
};

import React, { useState, useCallback, useEffect } from 'react';
import { VisualSettings } from './types';
import { HomeScreen } from './components/HomeScreen';
import { DesignStudio } from './components/DesignStudio';
import { SnakeLadderGame } from './components/SnakeLadderGame';

const VISUAL_SETTINGS_KEY = 'tanggaIlmuVisualSettings';

const initialVisualSettings: VisualSettings = {
  mainBackground: null,
  containerBackground: null,
};

// Define the top-level views available in the app
type AppView = 'home' | 'design' | 'game-snake-ladder';

export const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>('home');
  const [visualSettings, setVisualSettings] = useState<VisualSettings>(initialVisualSettings);

  // Load and apply visual settings from localStorage
  useEffect(() => {
    try {
      const savedSettings = localStorage.getItem(VISUAL_SETTINGS_KEY);
      if (savedSettings) {
        setVisualSettings(JSON.parse(savedSettings));
      }
    } catch (error) {
      console.error("Failed to load visual settings from localStorage", error);
    }
  }, []);

  useEffect(() => {
    if (visualSettings.mainBackground) {
      document.body.style.backgroundImage = `url(${visualSettings.mainBackground})`;
      document.body.style.backgroundSize = 'cover';
      document.body.style.backgroundPosition = 'center';
      document.body.style.backgroundAttachment = 'fixed';
    } else {
      document.body.style.backgroundImage = '';
      document.body.style.backgroundColor = ''; // Revert to CSS default
      document.body.classList.add('bg-stone-200'); // Ensure fallback
    }
  }, [visualSettings.mainBackground]);

  const handleSaveSettings = useCallback((newSettings: VisualSettings) => {
    setVisualSettings(newSettings);
    try {
      localStorage.setItem(VISUAL_SETTINGS_KEY, JSON.stringify(newSettings));
    } catch (error) {
      console.error("Failed to save visual settings to localStorage", error);
    }
    setCurrentView('home');
  }, []);

  const navigateToHome = useCallback(() => {
    setCurrentView('home');
  }, []);

  const navigateToDesign = useCallback(() => {
    setCurrentView('design');
  }, []);

  const startSnakeLadderGame = useCallback(() => {
    setCurrentView('game-snake-ladder');
  }, []);


  // --- Render Views ---

  if (currentView === 'home') {
    return (
      <HomeScreen 
        onStartSetup={startSnakeLadderGame} // Currently points to Snake Ladder
        onStartDesign={navigateToDesign} 
        visualSettings={visualSettings} 
      />
    );
  }

  if (currentView === 'design') {
    return (
      <DesignStudio 
        initialSettings={visualSettings} 
        onSave={handleSaveSettings} 
        onBack={navigateToHome} 
      />
    );
  }

  if (currentView === 'game-snake-ladder') {
    return (
      <SnakeLadderGame 
        visualSettings={visualSettings}
        onBackToMenu={navigateToHome}
      />
    );
  }

  return null;
};

export enum GameStage {
  Home = 'home',
  Setup = 'setup',
  Playing = 'playing',
  Finished = 'finished',
  Design = 'design', // Halaman baru untuk admin/desainer
}

export interface Player {
  id: number;
  name: string;
  position: number;
  color: string;
}

export interface SnakeOrLadder {
  start: number;
  end: number;
  // imageUrl removed - we use procedural SVG for ropes now
}

export type BoardActivities = Record<number, string>;

export type ActivityType = 'cognitive' | 'psychomotor';

export interface VisualSettings {
  mainBackground: string | null;
  containerBackground: string | null;
}

import React, { useState } from 'react';
import type { Player, SnakeOrLadder, BoardActivities, ActivityType, VisualSettings } from '../types';
import { BOARD_SIZE, PLAYER_COLORS } from '../constants';
import { GoogleGenAI, Type } from "@google/genai";

interface SetupScreenProps {
  onStartGame: (
    players: Player[],
    activities: BoardActivities,
    snakes: SnakeOrLadder[],
    ladders: SnakeOrLadder[],
    activityType: ActivityType
  ) => void;
  visualSettings: VisualSettings;
  onBack: () => void;
}

export const SetupScreen: React.FC<SetupScreenProps> = ({ onStartGame, visualSettings, onBack }) => {
  const [playerNames, setPlayerNames] = useState<string[]>(['Kelompok 1', 'Kelompok 2']);
  const [activities, setActivities] = useState<BoardActivities>({});

  // Menggunakan Tali (SVG) secara default, tanpa imageUrl eksternal
  const [snakes, setSnakes] = useState<SnakeOrLadder[]>([
    { start: 23, end: 5 }, 
    { start: 16, end: 8 }
  ]);
  const [ladders, setLadders] = useState<SnakeOrLadder[]>([{ start: 4, end: 14 }, { start: 11, end: 21 }]);

  // State for AI Activity Generation
  const [subject, setSubject] = useState('');
  const [topic, setTopic] = useState('');
  const [grade, setGrade] = useState('');
  const [activityType, setActivityType] = useState<ActivityType>('cognitive');
  const [isGeneratingActivities, setIsGeneratingActivities] = useState(false);


  const handleAddPlayer = () => {
    if (playerNames.length < PLAYER_COLORS.length) {
      setPlayerNames([...playerNames, `Kelompok ${playerNames.length + 1}`]);
    }
  };

  const handlePlayerNameChange = (index: number, name: string) => {
    const newPlayerNames = [...playerNames];
    newPlayerNames[index] = name;
    setPlayerNames(newPlayerNames);
  };

  const handleRemovePlayer = (index: number) => {
    setPlayerNames(playerNames.filter((_, i) => i !== index));
  };

  const handleActivityChange = (square: number, text: string) => {
    const newActivities = {...activities};
    if(text.trim() === '') {
        delete newActivities[square];
    } else {
        newActivities[square] = text;
    }
    setActivities(newActivities);
  };

  const handleSpecialSquareChange = (
    index: number,
    type: 'snakes' | 'ladders',
    field: 'start' | 'end',
    value: string
  ) => {
    const numValue = parseInt(value, 10);
    if (isNaN(numValue) || numValue < 1 || numValue > BOARD_SIZE) return;

    const list = type === 'snakes' ? [...snakes] : [...ladders];
    const updatedItem = { ...list[index], [field]: numValue };
    list[index] = updatedItem;

    if (type === 'snakes') setSnakes(list);
    else setLadders(list);
  };

  const handleAddSpecialSquare = (type: 'snakes' | 'ladders') => {
    if (type === 'snakes') {
      setSnakes([...snakes, { start: 0, end: 0 }]);
    } else {
      setLadders([...ladders, { start: 0, end: 0 }]);
    }
  };

  const handleRemoveSpecialSquare = (index: number, type: 'snakes' | 'ladders') => {
    if (type === 'snakes') setSnakes(snakes.filter((_, i) => i !== index));
    else setLadders(ladders.filter((_, i) => i !== index));
  };

  const handleGenerateActivities = async () => {
    if (!subject || !topic || !grade) {
      alert("Harap isi Mata Pelajaran, Materi, dan Kelas terlebih dahulu.");
      return;
    }
    setIsGeneratingActivities(true);
    try {
        const ai = new GoogleGenAI({ apiKey: import.meta.env.VITE_API_KEY });

        let prompt;

        if (activityType === 'psychomotor') {
            prompt = `Anda adalah seorang fasilitator kreatif dan instruktur yang merancang aktivitas untuk permainan Ular Tangga edukatif. Buatlah serangkaian TUGAS PRAKTIK atau PERAGAAN yang secara EKSKLUSIF berfokus pada konteks berikut:
- Mata Pelajaran: ${subject}
- Materi: ${topic}
- Tingkat: ${grade}

PENTING: Semua aktivitas HARUS berupa instruksi praktik/fisik/peragaan yang aman, relevan dengan materi (${topic}), dan dapat dilakukan oleh siswa tingkat ${grade}. JANGAN membuat pertanyaan teori atau kognitif (misalnya, "Sebutkan...", "Jelaskan...").
Contoh tugas untuk materi 'Sejarah Kemerdekaan': "Peragakan gaya Soekarno saat membacakan proklamasi.", "Berbarislah seperti pasukan Paskibraka selama 5 detik."
Contoh tugas untuk materi 'Biologi - Rantai Makanan': "Tiru gerakan kelinci melompat 3 kali.", "Peragakan cara tumbuhan melakukan fotosintesis dengan tanganmu."

Buatlah tugas untuk SETIAP KOTAK dari nomor 2 hingga ${BOARD_SIZE - 1}. Total harus ada ${BOARD_SIZE - 2} aktivitas. Jangan menempatkan aktivitas di kotak 1 atau kotak terakhir (${BOARD_SIZE}).

Kembalikan hasilnya dalam format JSON berupa sebuah ARRAY. Setiap elemen dalam array harus berupa OBJEK dengan dua properti: 'square' (nomor kotak sebagai ANGKA) dan 'activity' (tugas praktik sebagai STRING).
Contoh format: [ { "square": 2, "activity": "Lakukan gerakan menendang bola ke depan sebanyak 5 kali (tanpa bola)." }, { "square": 3, "activity": "Tiru gerakan seorang kiper menangkap bola 3 kali." }, ... ]`;
        } else { // 'cognitive'
            prompt = `Anda adalah seorang guru ahli yang merancang kuis untuk permainan Ular Tangga edukatif. Buatlah serangkaian pertanyaan singkat dan menarik yang secara EKSKLUSIF berfokus pada konteks berikut:
- Mata Pelajaran: ${subject}
- Materi: ${topic}
- Tingkat: ${grade}

PENTING: Semua pertanyaan HARUS relevan dengan materi (${topic}) dan sesuai untuk pemahaman siswa tingkat ${grade}. JANGAN membuat tugas fisik atau peragaan.

Buatlah pertanyaan untuk SETIAP KOTAK dari nomor 2 hingga ${BOARD_SIZE - 1}. Total harus ada ${BOARD_SIZE - 2} pertanyaan. Jangan menempatkan aktivitas di kotak 1 atau kotak terakhir (${BOARD_SIZE}).

Kembalikan hasilnya dalam format JSON berupa sebuah ARRAY. Setiap elemen dalam array harus berupa OBJEK dengan dua properti: 'square' (nomor kotak sebagai ANGKA) dan 'activity' (pertanyaan sebagai STRING).
Contoh format: [ { "square": 2, "activity": "Apa ibukota Indonesia?" }, { "square": 3, "activity": "Sebutkan 3 pahlawan nasional." }, ... ]`;
        }

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            square: {
                                type: Type.NUMBER,
                                description: 'Nomor kotak untuk aktivitas ini.'
                            },
                            activity: {
                                type: Type.STRING,
                                description: 'Teks pertanyaan atau tugas untuk kotak ini.'
                            }
                        },
                        required: ['square', 'activity']
                    }
                },
            },
        });

        const jsonText = response.text.trim();
        const generatedItems: { square: number; activity: string }[] = JSON.parse(jsonText);

        const newActivities: BoardActivities = {};
        for (const item of generatedItems) {
            if (item.square && item.activity) {
                newActivities[item.square] = item.activity;
            }
        }
        setActivities(newActivities);

    } catch (error) {
        console.error("Error generating activities:", error);
        alert("Gagal membuat aktivitas. Pastikan API Key Anda valid dan coba lagi.");
    } finally {
        setIsGeneratingActivities(false);
    }
  };

  const handleStart = () => {
    if (playerNames.some(name => name.trim() === '')) {
      alert('Nama pemain tidak boleh kosong.');
      return;
    }
    const finalPlayers: Player[] = playerNames.map((name, index) => ({
      id: index,
      name,
      position: 1,
      color: PLAYER_COLORS[index % PLAYER_COLORS.length],
    }));
    onStartGame(finalPlayers, activities, snakes, ladders, activityType);
  };

  const containerStyle: React.CSSProperties = visualSettings.containerBackground
    ? {
        backgroundImage: `url(${visualSettings.containerBackground})`,
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        color: 'white', // Ganti warna teks agar kontras
      }
    : {};

  const defaultClasses = "bg-stone-50";
  const hasCustomBg = !!visualSettings.containerBackground;

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4 sm:p-6">
      <div 
        className={`w-full max-w-5xl rounded-2xl shadow-2xl shadow-black/30 p-6 sm:p-8 space-y-8 border-2 ${hasCustomBg ? 'border-white/20' : 'border-stone-200'} ${!hasCustomBg ? defaultClasses : ''}`}
        style={containerStyle}
      >
        <div className="text-center relative">
          <button
            onClick={onBack}
            aria-label="Kembali ke menu utama"
            className={`absolute top-0 left-0 flex items-center gap-1 text-sm font-semibold transition-colors ${hasCustomBg ? 'text-sky-300 hover:text-sky-100' : 'text-sky-600 hover:text-sky-800'}`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M12.707 5.293a1 1 0 010 1.414L9.414 10l3.293 3.293a1 1 0 01-1.414 1.414l-4-4a1 1 0 010-1.414l4-4a1 1 0 011.414 0z" clipRule="evenodd" />
            </svg>
            Kembali
          </button>
          <h1 className={`text-4xl sm:text-5xl font-bold font-poppins ${hasCustomBg ? 'text-white' : 'text-slate-800'}`}>Tangga Ilmu</h1>
          <p className={`mt-2 text-lg ${hasCustomBg ? 'text-slate-200' : 'text-slate-500'}`}>Atur Permainan Edukatif Anda</p>
        </div>

        {/* AI Activity Generation Section */}
        <div className={`p-6 rounded-xl border ${hasCustomBg ? 'bg-black/30 border-white/20' : 'bg-stone-100 border-stone-300'}`}>
            <h2 className={`text-2xl font-semibold mb-4 font-poppins ${hasCustomBg ? 'text-white' : 'text-slate-700'}`}>1. Tentukan Konteks Pembelajaran</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
                <input type="text" placeholder="Mata Pelajaran (e.g., Sejarah)" value={subject} onChange={e => setSubject(e.target.value)} className={`p-3 border rounded-md focus:ring-2 focus:ring-orange-500 ${hasCustomBg ? 'bg-slate-800/50 border-slate-500 text-white placeholder-slate-400' : 'bg-white border-slate-300'}`}/>
                <input type="text" placeholder="Materi Spesifik (e.g., Proklamasi)" value={topic} onChange={e => setTopic(e.target.value)} className={`p-3 border rounded-md focus:ring-2 focus:ring-orange-500 ${hasCustomBg ? 'bg-slate-800/50 border-slate-500 text-white placeholder-slate-400' : 'bg-white border-slate-300'}`}/>
                <input type="text" placeholder="Tingkat Kelas (e.g., Kelas 5 SD)" value={grade} onChange={e => setGrade(e.target.value)} className={`p-3 border rounded-md focus:ring-2 focus:ring-orange-500 ${hasCustomBg ? 'bg-slate-800/50 border-slate-500 text-white placeholder-slate-400' : 'bg-white border-slate-300'}`}/>
            </div>
             <div className="flex justify-center gap-6 my-4">
                <label className={`flex items-center gap-2 cursor-pointer p-2 rounded-md ${hasCustomBg ? 'hover:bg-black/20' : 'hover:bg-stone-200'}`}>
                    <input 
                    type="radio" 
                    name="activityType" 
                    value="cognitive"
                    checked={activityType === 'cognitive'}
                    onChange={() => setActivityType('cognitive')}
                    className="w-5 h-5 text-orange-600 focus:ring-orange-500 border-slate-400"
                    />
                    <span className={`font-semibold ${hasCustomBg ? 'text-slate-200' : 'text-slate-700'}`}>Kognitif (Tanya Jawab)</span>
                </label>
                <label className={`flex items-center gap-2 cursor-pointer p-2 rounded-md ${hasCustomBg ? 'hover:bg-black/20' : 'hover:bg-stone-200'}`}>
                    <input 
                    type="radio" 
                    name="activityType" 
                    value="psychomotor"
                    checked={activityType === 'psychomotor'}
                    onChange={() => setActivityType('psychomotor')}
                    className="w-5 h-5 text-orange-600 focus:ring-orange-500 border-slate-400"
                    />
                    <span className={`font-semibold ${hasCustomBg ? 'text-slate-200' : 'text-slate-700'}`}>Psikomotor (Praktik)</span>
                </label>
            </div>
            <button
                onClick={handleGenerateActivities}
                disabled={isGeneratingActivities || !subject || !topic || !grade}
