                    <button onClick={handleFinalizeGame} className="flex-[3] py-3 bg-emerald-600 text-white text-xl rounded-lg font-bold hover:bg-emerald-700 shadow-lg transform transition hover:scale-105">
                        Mulai Petualangan! 🚀
