                        {/* SVG Connector Lines (The Road) - PRECISE COORDINATES 0-300 */}
                        <svg className="absolute inset-0 w-full h-full pointer-events-none z-0 overflow-visible" viewBox="0 0 300 300" preserveAspectRatio="none">
