import React, { useState, useCallback, useEffect } from 'react';
import { VisualSettings } from './types';
import { HomeScreen } from './components/HomeScreen';
import { DesignStudio } from './components/DesignStudio';
import { SnakeLadderGame } from './components/SnakeLadderGame';
import { LevelUpGame } from './components/LevelUpGame';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import { LoginScreen } from './components/LoginScreen';
import { ClassManager } from './components/ClassManager';
import { TopBar } from './components/TopBar';

const VISUAL_SETTINGS_KEY = 'tanggaIlmuVisualSettings';

const initialVisualSettings: VisualSettings = {
  mainBackground: null,
  containerBackground: null,
};

type AppView = 'home' | 'design' | 'game-snake-ladder' | 'game-level-up';

const AppContent: React.FC = () => {
  const { user, loading } = useAuth();
  const [currentView, setCurrentView] = useState<AppView>('home');
  const [visualSettings, setVisualSettings] = useState<VisualSettings>(initialVisualSettings);
  const [showClassManager, setShowClassManager] = useState(false);

  // Load and apply visual settings from localStorage
  useEffect(() => {
    try {
      const savedSettings = localStorage.getItem(VISUAL_SETTINGS_KEY);
      if (savedSettings) {
        setVisualSettings(JSON.parse(savedSettings));
      }
    } catch (error) {
      console.error("Failed to load visual settings from localStorage", error);
    }
  }, []);

  useEffect(() => {
    if (visualSettings.mainBackground) {
      document.body.style.backgroundImage = `url(${visualSettings.mainBackground})`;
      document.body.style.backgroundSize = 'cover';
      document.body.style.backgroundPosition = 'center';
      document.body.style.backgroundAttachment = 'fixed';
    } else {
      document.body.style.backgroundImage = '';
      document.body.style.backgroundColor = '';
      document.body.classList.add('bg-stone-200');
    }
  }, [visualSettings.mainBackground]);

  const handleSaveSettings = useCallback((newSettings: VisualSettings) => {
    setVisualSettings(newSettings);
    try {
      localStorage.setItem(VISUAL_SETTINGS_KEY, JSON.stringify(newSettings));
    } catch (error) {
      console.error("Failed to save visual settings to localStorage", error);
    }
    setCurrentView('home');
  }, []);

  if (loading) return <div className="min-h-screen flex items-center justify-center text-slate-500">Memuat data...</div>;
  if (!user) return <LoginScreen />;

  return (
    <>
        <TopBar 
            onOpenClassManager={() => setShowClassManager(true)} 
            onOpenDesign={() => setCurrentView('design')}
        />

        {/* Spacer for TopBar */}
        <div className="pt-16">
            {currentView === 'home' && (
                <HomeScreen 
                    onStartSnakeLadder={() => setCurrentView('game-snake-ladder')}
                    onStartLevelUp={() => setCurrentView('game-level-up')}
                    onStartDesign={() => setCurrentView('design')} 
                    visualSettings={visualSettings} 
                />
            )}

            {currentView === 'design' && (
                <DesignStudio 
                    initialSettings={visualSettings} 
                    onSave={handleSaveSettings} 
                    onBack={() => setCurrentView('home')} 
                />
            )}

            {currentView === 'game-snake-ladder' && (
                <SnakeLadderGame 
                    visualSettings={visualSettings}
                    onBackToMenu={() => setCurrentView('home')}
                />
            )}

            {currentView === 'game-level-up' && (
                <LevelUpGame 
                    visualSettings={visualSettings}
                    onBackToMenu={() => setCurrentView('home')}
                />
            )}
        </div>

        {showClassManager && <ClassManager onClose={() => setShowClassManager(false)} />}
    </>
  );
};

export const App: React.FC = () => {
    return (
        <AuthProvider>
            <AppContent />
        </AuthProvider>
    );
};

import React, { useState, useEffect } from 'react';
import type { Player, SnakeOrLadder, BoardActivities, ActivityType, VisualSettings, ClassData } from '../types';
import { BOARD_SIZE, PLAYER_COLORS } from '../constants';
import { GoogleGenAI, Type } from "@google/genai";
import { useAuth } from '../contexts/AuthContext';
import { collection, query, orderBy, onSnapshot } from 'firebase/firestore';
import { db } from '../firebase';
import { generateSmartGroups } from '../utils/grouping';
import { Users, Shuffle } from 'lucide-react';

interface SetupScreenProps {
  onStartGame: (
    players: Player[],
    activities: BoardActivities,
    snakes: SnakeOrLadder[],
    ladders: SnakeOrLadder[],
    activityType: ActivityType
  ) => void;
  visualSettings: VisualSettings;
  onBack: () => void;
}

export const SetupScreen: React.FC<SetupScreenProps> = ({ onStartGame, visualSettings, onBack }) => {
  const { user } = useAuth();

  // Players State
  const [inputMode, setInputMode] = useState<'manual' | 'class'>('manual');
  const [playerNames, setPlayerNames] = useState<string[]>(['Kelompok 1', 'Kelompok 2']);

  // Class Mode State
  const [classes, setClasses] = useState<ClassData[]>([]);
  const [selectedClassId, setSelectedClassId] = useState('');
  const [groupCount, setGroupCount] = useState(4);

  // Game Config State
  const [activities, setActivities] = useState<BoardActivities>({});
  const [snakes, setSnakes] = useState<SnakeOrLadder[]>([
    { start: 23, end: 5 }, 
    { start: 16, end: 8 }
  ]);
  const [ladders, setLadders] = useState<SnakeOrLadder[]>([{ start: 4, end: 14 }, { start: 11, end: 21 }]);

  // AI State
  const [subject, setSubject] = useState('');
  const [topic, setTopic] = useState('');
  const [grade, setGrade] = useState('');
  const [activityType, setActivityType] = useState<ActivityType>('cognitive');
  const [isGeneratingActivities, setIsGeneratingActivities] = useState(false);

  // Load Classes
  useEffect(() => {
    if (!user) return;
    const q = query(collection(db, 'users', user.uid, 'classes'), orderBy('name'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      setClasses(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as ClassData)));
    });
    return unsubscribe;
  }, [user]);

  // Generate Groups Logic
  const handleAutoGroup = () => {
      const cls = classes.find(c => c.id === selectedClassId);
      if (!cls || cls.students.length === 0) {
          alert("Pilih kelas yang memiliki siswa.");
          return;
      }

      const groups = generateSmartGroups(cls.students, groupCount);
      // We only use the names for the game state, but we can store members in a separate way if needed
      // For now, SnakeLadder uses 'name' string.
      // We can format name as "Kelompok 1 (Budi, Siti...)" but it might be too long.
      // Let's just use "Kelompok X" and maybe show details in tooltip?
      // Re-map to simple strings for this specific component state
      const names = groups.map(g => g.name); 
      setPlayerNames(names);
      alert(`Berhasil membagi ${cls.students.length} siswa menjadi ${groups.length} kelompok.`);
  };

  const handleAddPlayer = () => {
    if (playerNames.length < PLAYER_COLORS.length) {
      setPlayerNames([...playerNames, `Kelompok ${playerNames.length + 1}`]);
    }
  };

  const handlePlayerNameChange = (index: number, name: string) => {
    const newPlayerNames = [...playerNames];
    newPlayerNames[index] = name;
    setPlayerNames(newPlayerNames);
  };

  const handleRemovePlayer = (index: number) => {
    setPlayerNames(playerNames.filter((_, i) => i !== index));
  };

  const handleActivityChange = (square: number, text: string) => {
    const newActivities = {...activities};
    if(text.trim() === '') {
        delete newActivities[square];
    } else {
        newActivities[square] = text;
    }
    setActivities(newActivities);
  };

  const handleSpecialSquareChange = (
    index: number,
    type: 'snakes' | 'ladders',
    field: 'start' | 'end',
    value: string
  ) => {
    const numValue = parseInt(value, 10);
    if (isNaN(numValue) || numValue < 1 || numValue > BOARD_SIZE) return;

    const list = type === 'snakes' ? [...snakes] : [...ladders];
    const updatedItem = { ...list[index], [field]: numValue };
    list[index] = updatedItem;

    if (type === 'snakes') setSnakes(list);
    else setLadders(list);
  };

  const handleAddSpecialSquare = (type: 'snakes' | 'ladders') => {
    if (type === 'snakes') {
      setSnakes([...snakes, { start: 0, end: 0 }]);
    } else {
      setLadders([...ladders, { start: 0, end: 0 }]);
    }
  };

  const handleRemoveSpecialSquare = (index: number, type: 'snakes' | 'ladders') => {
    if (type === 'snakes') setSnakes(snakes.filter((_, i) => i !== index));
    else setLadders(ladders.filter((_, i) => i !== index));
  };

  const handleGenerateActivities = async () => {
    if (!subject || !topic || !grade) {
      alert("Harap isi Mata Pelajaran, Materi, dan Kelas terlebih dahulu.");
      return;
    }
    setIsGeneratingActivities(true);
    try {
        const ai = new GoogleGenAI({ apiKey: import.meta.env.VITE_API_KEY });

        let prompt;

        if (activityType === 'psychomotor') {
            prompt = `Anda adalah seorang fasilitator kreatif dan instruktur yang merancang aktivitas untuk permainan Ular Tangga edukatif. Buatlah serangkaian TUGAS PRAKTIK atau PERAGAAN yang secara EKSKLUSIF berfokus pada konteks berikut:
- Mata Pelajaran: ${subject}
- Materi: ${topic}
- Tingkat: ${grade}

PENTING: Semua aktivitas HARUS berupa instruksi praktik/fisik/peragaan yang aman, relevan dengan materi (${topic}), dan dapat dilakukan oleh siswa tingkat ${grade}. JANGAN membuat pertanyaan teori atau kognitif (misalnya, "Sebutkan...", "Jelaskan...").
Contoh tugas untuk materi 'Sejarah Kemerdekaan': "Peragakan gaya Soekarno saat membacakan proklamasi.", "Berbarislah seperti pasukan Paskibraka selama 5 detik."
Contoh tugas untuk materi 'Biologi - Rantai Makanan': "Tiru gerakan kelinci melompat 3 kali.", "Peragakan cara tumbuhan melakukan fotosintesis dengan tanganmu."

Buatlah tugas untuk SETIAP KOTAK dari nomor 2 hingga ${BOARD_SIZE - 1}. Total harus ada ${BOARD_SIZE - 2} aktivitas. Jangan menempatkan aktivitas di kotak 1 atau kotak terakhir (${BOARD_SIZE}).

Kembalikan hasilnya dalam format JSON berupa sebuah ARRAY. Setiap elemen dalam array harus berupa OBJEK dengan dua properti: 'square' (nomor kotak sebagai ANGKA) dan 'activity' (tugas praktik sebagai STRING).
Contoh format: [ { "square": 2, "activity": "Lakukan gerakan menendang bola ke depan sebanyak 5 kali (tanpa bola)." }, { "square": 3, "activity": "Tiru gerakan seorang kiper menangkap bola 3 kali." }, ... ]`;
        } else { // 'cognitive'
            prompt = `Anda adalah seorang guru ahli yang merancang kuis untuk permainan Ular Tangga edukatif. Buatlah serangkaian pertanyaan singkat dan menarik yang secara EKSKLUSIF berfokus pada konteks berikut:
- Mata Pelajaran: ${subject}
- Materi: ${topic}
- Tingkat: ${grade}

PENTING: Semua pertanyaan HARUS relevan dengan materi (${topic}) dan sesuai untuk pemahaman siswa tingkat ${grade}. JANGAN membuat tugas fisik atau peragaan.

Buatlah pertanyaan untuk SETIAP KOTAK dari nomor 2 hingga ${BOARD_SIZE - 1}. Total harus ada ${BOARD_SIZE - 2} pertanyaan. Jangan menempatkan aktivitas di kotak 1 atau kotak terakhir (${BOARD_SIZE}).

Kembalikan hasilnya dalam format JSON berupa sebuah ARRAY. Setiap elemen dalam array harus berupa OBJEK dengan dua properti: 'square' (nomor kotak sebagai ANGKA) dan 'activity' (pertanyaan sebagai STRING).
Contoh format: [ { "square": 2, "activity": "Apa ibukota Indonesia?" }, { "square": 3, "activity": "Sebutkan 3 pahlawan nasional." }, ... ]`;
        }

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            square: {
                                type: Type.NUMBER,
                                description: 'Nomor kotak untuk aktivitas ini.'
                            },
                            activity: {
                                type: Type.STRING,
                                description: 'Teks pertanyaan atau tugas untuk kotak ini.'
                            }
                        },
                        required: ['square', 'activity']
                    }
                },
            },
        });

        const jsonText = response.text.trim();
        const generatedItems: { square: number; activity: string }[] = JSON.parse(jsonText);

        const newActivities: BoardActivities = {};
        for (const item of generatedItems) {
            if (item.square && item.activity) {
                newActivities[item.square] = item.activity;
            }
        }
        setActivities(newActivities);

    } catch (error) {
        console.error("Error generating activities:", error);
        alert("Gagal membuat aktivitas. Pastikan API Key Anda valid dan coba lagi.");
    } finally {
        setIsGeneratingActivities(false);
    }
  };

  const handleStart = () => {
    if (playerNames.some(name => name.trim() === '')) {
      alert('Nama pemain tidak boleh kosong.');
      return;
    }
    const finalPlayers: Player[] = playerNames.map((name, index) => ({
      id: index,
      name,
      position: 1,
      color: PLAYER_COLORS[index % PLAYER_COLORS.length],
    }));
    onStartGame(finalPlayers, activities, snakes, ladders, activityType);
  };

  const containerStyle: React.CSSProperties = visualSettings.containerBackground
    ? {
        backgroundImage: `url(${visualSettings.containerBackground})`,
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        color: 'white',
      }
    : {};

  const defaultClasses = "bg-stone-50";
  const hasCustomBg = !!visualSettings.containerBackground;
  const inputClass = `w-full p-2 border rounded-md focus:ring-2 focus:ring-orange-500 focus:border-orange-500 ${hasCustomBg ? 'bg-slate-800/50 border-slate-500 text-white placeholder-slate-400' : 'bg-white border-slate-300'}`;


  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4 sm:p-6 pb-20">
      <div 
        className={`w-full max-w-5xl rounded-2xl shadow-2xl shadow-black/30 p-6 sm:p-8 space-y-8 border-2 ${hasCustomBg ? 'border-white/20' : 'border-stone-200'} ${!hasCustomBg ? defaultClasses : ''}`}
        style={containerStyle}
      >
        <div className="text-center relative">
          <button
            onClick={onBack}
            className={`absolute top-0 left-0 flex items-center gap-1 text-sm font-semibold transition-colors ${hasCustomBg ? 'text-sky-300 hover:text-sky-100' : 'text-sky-600 hover:text-sky-800'}`}
          >
            ← Kembali
          </button>
          <h1 className={`text-4xl sm:text-5xl font-bold font-poppins ${hasCustomBg ? 'text-white' : 'text-slate-800'}`}>Tangga Ilmu</h1>
          <p className={`mt-2 text-lg ${hasCustomBg ? 'text-slate-200' : 'text-slate-500'}`}>Atur Permainan Edukatif Anda</p>
        </div>

        {/* AI Activity Generation Section */}
        <div className={`p-6 rounded-xl border ${hasCustomBg ? 'bg-black/30 border-white/20' : 'bg-stone-100 border-stone-300'}`}>
            <h2 className={`text-2xl font-semibold mb-4 font-poppins ${hasCustomBg ? 'text-white' : 'text-slate-700'}`}>1. Tentukan Konteks Pembelajaran</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
                <input type="text" placeholder="Mata Pelajaran (e.g., Sejarah)" value={subject} onChange={e => setSubject(e.target.value)} className={inputClass}/>
                <input type="text" placeholder="Materi Spesifik (e.g., Proklamasi)" value={topic} onChange={e => setTopic(e.target.value)} className={inputClass}/>
                <input type="text" placeholder="Tingkat Kelas (e.g., Kelas 5 SD)" value={grade} onChange={e => setGrade(e.target.value)} className={inputClass}/>
            </div>
             <div className="flex justify-center gap-6 my-4">
                <label className={`flex items-center gap-2 cursor-pointer p-2 rounded-md ${hasCustomBg ? 'hover:bg-black/20' : 'hover:bg-stone-200'}`}>
                    <input type="radio" name="activityType" value="cognitive" checked={activityType === 'cognitive'} onChange={() => setActivityType('cognitive')} className="w-5 h-5 text-orange-600 focus:ring-orange-500 border-slate-400" />
                    <span className={`font-semibold ${hasCustomBg ? 'text-slate-200' : 'text-slate-700'}`}>Kognitif (Tanya Jawab)</span>
                </label>
                <label className={`flex items-center gap-2 cursor-pointer p-2 rounded-md ${hasCustomBg ? 'hover:bg-black/20' : 'hover:bg-stone-200'}`}>
                    <input type="radio" name="activityType" value="psychomotor" checked={activityType === 'psychomotor'} onChange={() => setActivityType('psychomotor')} className="w-5 h-5 text-orange-600 focus:ring-orange-500 border-slate-400" />
                    <span className={`font-semibold ${hasCustomBg ? 'text-slate-200' : 'text-slate-700'}`}>Psikomotor (Praktik)</span>
                </label>
            </div>
            <button
                onClick={handleGenerateActivities}
                disabled={isGeneratingActivities || !subject || !topic || !grade}
                className="w-full bg-orange-600 text-white font-bold text-lg py-3 rounded-lg hover:bg-orange-700 transition-all transform hover:scale-105 shadow disabled:bg-slate-400 disabled:cursor-not-allowed disabled:transform-none"
            >
                {isGeneratingActivities ? 'Sedang Membuat Aktivitas...' : 'Buat Aktivitas dengan AI'}
            </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-6">
          {/* Column 1: Activities Review */}
          <div>
            <h2 className={`text-2xl font-semibold border-b-2 pb-2 mb-4 font-poppins ${hasCustomBg ? 'text-white border-white/20' : 'text-slate-700 border-stone-200'}`}>2. Tinjau Aktivitas Kotak</h2>
            <div className="max-h-[450px] overflow-y-auto space-y-3 pr-3">
              {[...Array(BOARD_SIZE)].map((_, i) => {
                const squareNum = i + 1;
                return (
                  <div key={squareNum}>
                    <label className={`font-semibold ${hasCustomBg ? 'text-slate-200' : 'text-slate-600'}`}>Kotak {squareNum}:</label>
                    <textarea
                      value={activities[squareNum] || ''}
                      onChange={(e) => handleActivityChange(squareNum, e.target.value)}
                      placeholder="Kosong (atau isi manual)"
                      className={inputClass}
                      rows={2}
                    />
                  </div>
                );
              })}
            </div>
          </div>

          {/* Column 2: Players & Special Squares */}
          <div className="space-y-6">
            <h2 className={`text-2xl font-semibold -mb-2 font-poppins ${hasCustomBg ? 'text-white' : 'text-slate-700'}`}>3. Atur Pemain & Papan</h2>

            {/* Players Setup */}
            <div>
              <div className="flex gap-2 mb-4 bg-slate-100 p-1 rounded-lg w-fit">
                <button 
                    onClick={() => setInputMode('manual')}
                    className={`px-3 py-1 text-sm font-bold rounded-md transition-colors ${inputMode === 'manual' ? 'bg-white shadow text-orange-600' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    Manual
                </button>
                <button 
                    onClick={() => setInputMode('class')}
                    className={`px-3 py-1 text-sm font-bold rounded-md transition-colors ${inputMode === 'class' ? 'bg-white shadow text-emerald-600' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    Dari Kelas
                </button>
              </div>

              {inputMode === 'class' ? (
                  <div className={`p-4 rounded-lg border-2 border-emerald-400/50 ${hasCustomBg ? 'bg-emerald-900/20' : 'bg-emerald-50'}`}>
                      <label className="block text-sm font-bold mb-1">Pilih Kelas</label>
                      <select 
                        value={selectedClassId} 
                        onChange={e => setSelectedClassId(e.target.value)}
                        className={`w-full p-2 rounded mb-3 ${hasCustomBg ? 'bg-slate-800 text-white' : 'bg-white border-slate-300 border'}`}
                      >
                          <option value="">-- Pilih Kelas --</option>
                          {classes.map(c => <option key={c.id} value={c.id}>{c.name} ({c.students.length} Siswa)</option>)}
                      </select>

                      <label className="block text-sm font-bold mb-1">Jumlah Kelompok</label>
                      <input 
                        type="number" 
                        min={2} 
                        max={8} 
                        value={groupCount}
                        onChange={e => setGroupCount(parseInt(e.target.value))}
                        className={`w-full p-2 rounded mb-3 ${hasCustomBg ? 'bg-slate-800 text-white' : 'bg-white border-slate-300 border'}`}
                      />

                      <button onClick={handleAutoGroup} className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-2 rounded flex items-center justify-center gap-2">
                          <Shuffle size={18} />
                          Buat Kelompok Otomatis
                      </button>
                  </div>
              ) : (
                <>
                  <h3 className={`text-xl font-medium mb-2 ${hasCustomBg ? 'text-slate-200' : 'text-slate-600'}`}>Pemain Manual</h3>
                  {playerNames.map((name, index) => (
                    <div key={index} className="flex items-center gap-2 mb-2">
                      <span className={`w-6 h-6 rounded-full ${PLAYER_COLORS[index % PLAYER_COLORS.length]}`}></span>
                      <input
                        type="text"
                        value={name}
                        onChange={(e) => handlePlayerNameChange(index, e.target.value)}
                        className={inputClass}
                      />
                      <button onClick={() => handleRemovePlayer(index)} className="text-red-500 hover:text-red-700 p-1">✕</button>
                    </div>
                  ))}
                  {playerNames.length < PLAYER_COLORS.length && (
                    <button onClick={handleAddPlayer} className={`mt-2 w-full font-semibold border-2 rounded-md py-2 transition-colors ${hasCustomBg ? 'text-orange-300 border-orange-400 hover:bg-black/20' : 'text-orange-600 border-orange-500 hover:bg-orange-50'}`}>
                      + Tambah Pemain
                    </button>
                  )}
                </>
              )}
            </div>

            {/* Special Squares Setup */}
            <div className="space-y-4">
              <SpecialSquareSetup 
                  title="Tangga (Naik)" 
                  items={ladders} 
                  onChange={(i, f, v) => handleSpecialSquareChange(i, 'ladders', f, v)} 
                  onAdd={() => handleAddSpecialSquare('ladders')} 
                  onRemove={(i) => handleRemoveSpecialSquare(i, 'ladders')}
                  hasCustomBg={hasCustomBg}
              />
              <SpecialSquareSetup 
                  title="Tali (Turun)" 
                  items={snakes} 
                  onChange={(i, f, v) => handleSpecialSquareChange(i, 'snakes', f, v)} 
                  onAdd={() => handleAddSpecialSquare('snakes')} 
                  onRemove={(i) => handleRemoveSpecialSquare(i, 'snakes')}
                  hasCustomBg={hasCustomBg}
              />
            </div>
          </div>
        </div>

        <div className={`pt-6 border-t ${hasCustomBg ? 'border-white/20' : 'border-slate-200'}`}>
          <button onClick={handleStart} className="w-full bg-emerald-600 text-white font-bold text-xl py-4 rounded-lg hover:bg-emerald-700 transition-transform transform hover:scale-105 shadow-lg">
            Mulai Permainan
          </button>
        </div>
      </div>
    </div>
  );
};

interface SpecialSquareSetupProps {
    title: string;
    items: SnakeOrLadder[];
    onChange: (index: number, field: 'start' | 'end', value: string) => void;
    onAdd: () => void;
    onRemove: (index: number) => void;
    hasCustomBg: boolean;
}

const SpecialSquareSetup: React.FC<SpecialSquareSetupProps> = ({ title, items, onChange, onAdd, onRemove, hasCustomBg }) => {
    const baseTitle = title.split(' ')[0];

    return (
        <div>
            <h3 className={`text-xl font-medium mb-2 ${hasCustomBg ? 'text-slate-200' : 'text-slate-600'}`}>{title}</h3>
            {items.map((item, index) => (
                <div key={index} className={`p-2 border rounded-lg mb-2 ${hasCustomBg ? 'bg-black/20 border-white/10' : 'bg-stone-100'}`}>
                  <div className="flex items-center gap-2">
                      <input type="number" value={item.start || ''} onChange={e => onChange(index, 'start', e.target.value)} className={`w-16 p-2 border rounded-md ${hasCustomBg ? 'bg-slate-800/50 border-slate-500 text-white' : 'bg-white'}`} placeholder="Dari" />
                      <span>→</span>
                      <input type="number" value={item.end || ''} onChange={e => onChange(index, 'end', e.target.value)} className={`w-16 p-2 border rounded-md ${hasCustomBg ? 'bg-slate-800/50 border-slate-500 text-white' : 'bg-white'}`} placeholder="Ke" />
                      <button onClick={() => onRemove(index)} className="text-red-500 hover:text-red-700 p-1 ml-auto">✕</button>
                  </div>
                </div>
            ))}
            <button onClick={onAdd} className={`mt-1 w-full text-sm font-semibold border-2 border-dashed rounded-md py-1 transition-colors ${hasCustomBg ? 'text-slate-400 border-slate-500 hover:bg-black/20' : 'text-slate-600 border-slate-400 hover:bg-stone-200'}`}>
              + Tambah {baseTitle}
            </button>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { GameStage, Player, LevelContent, ActivityType, VisualSettings, LevelTask, ClassData } from '../types';
import { PLAYER_COLORS } from '../constants';
import { GoogleGenAI, Type } from "@google/genai";
import { VictoryScreen } from './VictoryScreen';
import { useAuth } from '../contexts/AuthContext';
import { collection, query, orderBy, onSnapshot } from 'firebase/firestore';
import { db } from '../firebase';
import { generateSmartGroups } from '../utils/grouping';
import { Shuffle } from 'lucide-react';

// --- TYPES INTERNAL ---
type SetupStep = 'input' | 'review';

// --- SETUP COMPONENT ---
interface LevelUpSetupProps {
    onStartGame: (players: Player[], content: LevelContent, type: ActivityType) => void;
    visualSettings: VisualSettings;
    onBack: () => void;
}

const LevelUpSetup: React.FC<LevelUpSetupProps> = ({ onStartGame, visualSettings, onBack }) => {
    const { user } = useAuth();

    // State Input
    const [step, setStep] = useState<SetupStep>('input');
    const [subject, setSubject] = useState('');
    const [grade, setGrade] = useState('');
    const [objective, setObjective] = useState('');
    const [activityType, setActivityType] = useState<ActivityType>('cognitive');

    // Player State
    const [inputMode, setInputMode] = useState<'manual' | 'class'>('manual');
    const [playerNames, setPlayerNames] = useState<string[]>(['Tim A', 'Tim B']);
    const [classes, setClasses] = useState<ClassData[]>([]);
    const [selectedClassId, setSelectedClassId] = useState('');
    const [groupCount, setGroupCount] = useState(4);

    // State Processing
    const [isGenerating, setIsGenerating] = useState(false);
    const [draftLevels, setDraftLevels] = useState<LevelContent>({});

    // Load Classes
    useEffect(() => {
        if (!user) return;
        const q = query(collection(db, 'users', user.uid, 'classes'), orderBy('name'));
        const unsubscribe = onSnapshot(q, (snapshot) => {
            setClasses(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as ClassData)));
        });
        return unsubscribe;
    }, [user]);

    const handleAutoGroup = () => {
        const cls = classes.find(c => c.id === selectedClassId);
        if (!cls || cls.students.length === 0) {
            alert("Pilih kelas yang memiliki siswa.");
            return;
        }

        const groups = generateSmartGroups(cls.students, groupCount);
        const names = groups.map(g => g.name); 
        setPlayerNames(names);
        alert(`Berhasil membagi ${cls.students.length} siswa menjadi ${groups.length} kelompok.`);
    };

    const handleAddPlayer = () => {
        if (playerNames.length < PLAYER_COLORS.length) setPlayerNames([...playerNames, `Tim ${String.fromCharCode(65 + playerNames.length)}`]);
    };

    // Step 1: Generate Content
    const handleGenerate = async () => {
        if (!subject || !grade || !objective) {
            alert("Mohon lengkapi Mata Pelajaran, Kelas, dan Tujuan Pembelajaran.");
            return;
        }

        setIsGenerating(true);
        try {
            const ai = new GoogleGenAI({ apiKey: import.meta.env.VITE_API_KEY });

            const promptContext = activityType === 'cognitive' 
                ? "Pertanyaan Kuis/Soal (Kognitif)" 
                : "Tantangan Fisik/Praktik (Psikomotor)";

            const prompt = `Anda adalah desainer game edukasi level bertingkat. Buatlah 9 konten ${promptContext} untuk permainan "Level Up".

            Konteks:
            - Mapel: ${subject}
            - Kelas: ${grade}
            - TUJUAN AKHIR (Level 9): ${objective}

            Aturan Tingkat Kesulitan:
            - Level 1-2: Sangat Mudah (Pengenalan/Pemanasan).
            - Level 3-4: Mudah.
            - Level 5-6: Menengah.
            - Level 7-8: Sulit.
            - Level 9: PUNCAK (Harus menguji ketercapaian "${objective}").

            Output JSON Array dengan 9 objek. Format:
            [
                { "level": 1, "difficulty": "Mudah", "content": "..." },
                ...
                { "level": 9, "difficulty": "Puncak", "content": "..." }
            ]`;

            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash',
                contents: prompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                level: { type: Type.NUMBER },
                                difficulty: { type: Type.STRING },
                                content: { type: Type.STRING }
                            },
                            required: ['level', 'content', 'difficulty']
                        }
                    },
                },
            });

            const generatedData = JSON.parse(response.text.trim()) as LevelTask[];
            const contentMap: LevelContent = {};

            // Fill 1-9
            for(let i=1; i<=9; i++) {
                const found = generatedData.find(d => d.level === i);
                contentMap[i] = found || { level: i, difficulty: 'N/A', content: 'Konten tidak tergenerate' };
            }

            setDraftLevels(contentMap);
            setStep('review'); // Pindah ke mode edit

        } catch (error) {
            console.error(error);
            alert("Gagal membuat konten AI. Cek API Key.");
        } finally {
            setIsGenerating(false);
        }
    };

    // Step 2: Update Manual
    const handleUpdateLevelContent = (level: number, newContent: string) => {
        setDraftLevels(prev => ({
            ...prev,
            [level]: { ...prev[level], content: newContent }
        }));
    };

    // Step 3: Start Game
    const handleFinalizeGame = () => {
        const finalPlayers: Player[] = playerNames.map((name, index) => ({
            id: index,
            name,
            position: 1, 
            color: PLAYER_COLORS[index % PLAYER_COLORS.length],
        }));
        onStartGame(finalPlayers, draftLevels, activityType);
    };

    const hasCustomBg = !!visualSettings.containerBackground;
    const textColor = hasCustomBg ? 'text-white' : 'text-slate-800';
    const subTextColor = hasCustomBg ? 'text-slate-200' : 'text-slate-600';
    const inputClass = `w-full p-3 rounded border focus:ring-2 focus:ring-orange-500 ${hasCustomBg ? 'bg-slate-800/50 border-slate-500 text-white placeholder-slate-400' : 'bg-white border-slate-300'}`;

    // --- RENDER STEP 1: INPUT ---
    if (step === 'input') {
        return (
            <div className="min-h-screen flex items-center justify-center p-4">
                 <div className={`w-full max-w-4xl rounded-2xl shadow-2xl p-8 border-2 space-y-6 ${hasCustomBg ? 'bg-black/40 border-white/20' : 'bg-stone-50 border-stone-200'}`} style={visualSettings.containerBackground ? { backgroundImage: `url(${visualSettings.containerBackground})`, backgroundSize: 'cover' } : {}}>

                    <div className="relative text-center">
                        <button onClick={onBack} className={`absolute left-0 top-0 text-sm font-bold ${hasCustomBg ? 'text-sky-300' : 'text-sky-600'}`}>← Kembali</button>
                        <h1 className={`text-4xl font-bold font-poppins ${textColor}`}>Setup Level Up</h1>
                        <p className={subTextColor}>Taklukkan 9 Tingkat Tantangan!</p>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div className="space-y-4">
                            <h3 className={`text-xl font-bold border-b pb-2 ${textColor}`}>1. Konteks Pembelajaran</h3>
                            <input type="text" placeholder="Mata Pelajaran (Misal: IPA)" value={subject} onChange={e => setSubject(e.target.value)} className={inputClass} />
                            <input type="text" placeholder="Fase / Kelas (Misal: Kelas 4)" value={grade} onChange={e => setGrade(e.target.value)} className={inputClass} />
                            <textarea rows={3} placeholder="Tujuan Pembelajaran Akhir (Untuk Level 9)" value={objective} onChange={e => setObjective(e.target.value)} className={inputClass} />

                            <div className="flex gap-4 pt-2">
                                 <label className={`flex items-center gap-2 cursor-pointer ${textColor}`}>
                                    <input type="radio" checked={activityType === 'cognitive'} onChange={() => setActivityType('cognitive')} className="w-5 h-5 text-orange-600" />
                                    <span>Kognitif (Soal)</span>
                                </label>
                                <label className={`flex items-center gap-2 cursor-pointer ${textColor}`}>
                                    <input type="radio" checked={activityType === 'psychomotor'} onChange={() => setActivityType('psychomotor')} className="w-5 h-5 text-orange-600" />
                                    <span>Psikomotor (Gerak)</span>
                                </label>
                            </div>
                        </div>

                        <div className="space-y-4">
                            <h3 className={`text-xl font-bold border-b pb-2 ${textColor}`}>2. Kelompok Peserta</h3>

                             <div className="flex gap-2 mb-2 bg-slate-100 p-1 rounded-lg w-fit">
                                <button 
                                    onClick={() => setInputMode('manual')}
                                    className={`px-3 py-1 text-sm font-bold rounded-md transition-colors ${inputMode === 'manual' ? 'bg-white shadow text-orange-600' : 'text-slate-500 hover:text-slate-700'}`}
                                >
                                    Manual
                                </button>
                                <button 
                                    onClick={() => setInputMode('class')}
                                    className={`px-3 py-1 text-sm font-bold rounded-md transition-colors ${inputMode === 'class' ? 'bg-white shadow text-emerald-600' : 'text-slate-500 hover:text-slate-700'}`}
                                >
                                    Dari Kelas
                                </button>
                            </div>

                            {inputMode === 'class' ? (
                                <div className={`p-4 rounded-lg border-2 border-emerald-400/50 ${hasCustomBg ? 'bg-emerald-900/20' : 'bg-emerald-50'}`}>
                                    <select 
                                        value={selectedClassId} 
                                        onChange={e => setSelectedClassId(e.target.value)}
                                        className={`w-full p-2 rounded mb-3 text-sm ${hasCustomBg ? 'bg-slate-800 text-white' : 'bg-white border-slate-300 border'}`}
                                    >
                                        <option value="">-- Pilih Kelas --</option>
                                        {classes.map(c => <option key={c.id} value={c.id}>{c.name} ({c.students.length} Siswa)</option>)}
                                    </select>

                                    <input 
                                        type="number" 
                                        min={2} 
                                        max={8} 
                                        placeholder="Jumlah Kelompok"
                                        value={groupCount}
                                        onChange={e => setGroupCount(parseInt(e.target.value))}
                                        className={`w-full p-2 rounded mb-3 text-sm ${hasCustomBg ? 'bg-slate-800 text-white' : 'bg-white border-slate-300 border'}`}
                                    />

                                    <button onClick={handleAutoGroup} className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-2 rounded flex items-center justify-center gap-2 text-sm">
                                        <Shuffle size={16} />
                                        Buat Kelompok
                                    </button>
                                </div>
                            ) : (
                                <div className="max-h-60 overflow-y-auto space-y-2 pr-2">
                                    {playerNames.map((name, idx) => (
                                        <div key={idx} className="flex gap-2">
                                            <div className={`w-10 h-10 rounded-full flex-shrink-0 ${PLAYER_COLORS[idx % PLAYER_COLORS.length]}`}></div>
                                            <input value={name} onChange={(e) => {
                                                const newNames = [...playerNames];
                                                newNames[idx] = e.target.value;
                                                setPlayerNames(newNames);
                                            }} className={inputClass} />
                                            <button onClick={() => setPlayerNames(playerNames.filter((_, i) => i !== idx))} className="text-red-500 font-bold px-2">✕</button>
                                        </div>
                                    ))}
                                     {playerNames.length < 8 && (
                                        <button onClick={handleAddPlayer} className={`w-full py-2 border-2 border-dashed rounded font-bold ${hasCustomBg ? 'border-slate-400 text-slate-300 hover:bg-white/10' : 'border-slate-400 text-slate-500 hover:bg-slate-100'}`}>+ Tambah Kelompok</button>
                                    )}
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="pt-4 border-t border-slate-400/30">
                        <button 
                            onClick={handleGenerate} 
                            disabled={isGenerating}
                            className="w-full bg-orange-600 text-white text-xl font-bold py-4 rounded-xl shadow-lg hover:bg-orange-700 disabled:bg-slate-500 transition-all transform hover:scale-105"
                        >
                            {isGenerating ? 'Sedang Meracik Level...' : 'Buat Konten & Review'}
                        </button>
                    </div>
                 </div>
            </div>
        );
    }

    // --- RENDER STEP 2: REVIEW ---
    return (
        <div className="min-h-screen flex items-center justify-center p-4">
            <div className={`w-full max-w-6xl h-[90vh] flex flex-col rounded-2xl shadow-2xl p-6 border-2 ${hasCustomBg ? 'bg-black/80 border-white/20' : 'bg-stone-50 border-stone-200'}`}>
                <div className="flex justify-between items-center mb-4 border-b pb-2">
                    <h2 className={`text-3xl font-bold font-poppins ${textColor}`}>Review & Edit Level</h2>
                    <button onClick={() => setStep('input')} className="text-sm text-red-400 hover:text-red-500 underline">Ubah Pengaturan Awal</button>
                </div>

                <div className="flex-grow overflow-y-auto grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 pr-2 pb-4">
                    {[1, 2, 3, 4, 5, 6, 7, 8, 9].map((levelNum) => {
                        const data = draftLevels[levelNum];
                        return (
                            <div key={levelNum} className={`p-4 rounded-lg border-2 flex flex-col ${hasCustomBg ? 'bg-slate-800 border-slate-600' : 'bg-white border-slate-200'}`}>
                                <div className="flex justify-between mb-2">
                                    <span className="font-bold text-orange-500">Level {levelNum}</span>
                                    <span className="text-xs bg-slate-200 px-2 py-1 rounded text-slate-700">{data?.difficulty}</span>
                                </div>
                                <textarea 
                                    value={data?.content || ''}
                                    onChange={(e) => handleUpdateLevelContent(levelNum, e.target.value)}
                                    className={`flex-grow w-full p-2 text-sm rounded border resize-none focus:ring-2 focus:ring-orange-500 ${hasCustomBg ? 'bg-slate-900 text-white border-slate-700' : 'bg-slate-50 text-slate-800 border-slate-300'}`}
                                    rows={4}
                                />
                            </div>
                        )
                    })}
                </div>

                <div className="pt-4 mt-auto border-t border-slate-500/30 flex gap-4">
                    <button onClick={() => setStep('input')} className="flex-1 py-3 bg-slate-500 text-white rounded-lg font-bold hover:bg-slate-600">
                        Batal
                    </button>
                    <button onClick={handleFinalizeGame} className="flex-[3] py-3 bg-emerald-600 text-white text-xl rounded-lg font-bold hover:bg-emerald-700 shadow-lg transform transition hover:scale-105">
                        Mulai Petualangan! 🚀
                    </button>
                </div>
            </div>
        </div>
    );
};

// --- MAIN GAME COMPONENT ---

interface LevelUpGameProps {
    visualSettings: VisualSettings;
    onBackToMenu: () => void;
}

export const LevelUpGame: React.FC<LevelUpGameProps> = ({ visualSettings, onBackToMenu }) => {
    const [stage, setStage] = useState<GameStage>(GameStage.Setup);
    const [players, setPlayers] = useState<Player[]>([]);
    const [levels, setLevels] = useState<LevelContent>({});
    const [activeGroupIndex, setActiveGroupIndex] = useState<number | null>(null);
    const [modalTask, setModalTask] = useState<LevelTask | null>(null);
    const [winner, setWinner] = useState<Player | null>(null);

    const handleStart = (newPlayers: Player[], newLevels: LevelContent) => {
        setPlayers(newPlayers);
        setLevels(newLevels);
        setStage(GameStage.Playing);
    };

    const handleGroupClick = (index: number) => {
        const player = players[index];
        // Jika sudah menang (seharusnya tidak mungkin diklik jika UI dilock), return
        if (player.position > 9) return;

        setActiveGroupIndex(index);
        setModalTask(levels[player.position]);
    };

    const handleValidation = (passed: boolean) => {
        if (activeGroupIndex === null) return;

        if (passed) {
            setPlayers(prev => {
                const newPlayers = [...prev];
                const player = newPlayers[activeGroupIndex];

                // Jika player ada di level 9 dan lulus, dia menang.
                if (player.position === 9) {
                    setWinner(player);
                    setTimeout(() => setStage(GameStage.Finished), 500);
                } else {
                    player.position += 1; // Naik Level
                }
                return newPlayers;
            });
        }
        setModalTask(null);
        setActiveGroupIndex(null);
    };

    if (stage === GameStage.Setup) {
        return <LevelUpSetup onStartGame={handleStart} visualSettings={visualSettings} onBack={onBackToMenu} />;
    }

    if (stage === GameStage.Finished && winner) {
        return <VictoryScreen winner={winner} onNewGame={onBackToMenu} onResetGame={() => setStage(GameStage.Setup)} />;
    }

    const hasCustomBg = !!visualSettings.containerBackground;
    const bgClass = hasCustomBg ? 'bg-black/40 border-white/20 text-white' : 'bg-white border-slate-200 text-slate-800';

    return (
        <div className="min-h-screen p-2 sm:p-4 flex flex-col items-center">
            {/* Header */}
            <div className={`w-full max-w-7xl flex justify-between items-center mb-4 p-4 rounded-xl border-2 ${bgClass}`}>
                <h1 className="text-2xl sm:text-3xl font-bold font-poppins">Level Up Adventure</h1>
                <button onClick={onBackToMenu} className="bg-red-500 hover:bg-red-600 text-white px-4 py-2 rounded font-bold text-sm">Keluar</button>
            </div>

            <div className="flex flex-col lg:flex-row gap-6 w-full max-w-7xl flex-grow h-full">

                {/* --- BOARD AREA --- */}
                <div className="flex-grow relative bg-slate-200/50 rounded-2xl border-4 border-slate-400 p-4 sm:p-8 flex items-center justify-center min-h-[600px]">

                    {/* Container Board (Responsive but Large) */}
                    <div className="relative w-full max-w-3xl aspect-square">

                        {/* SVG Connector Lines (The Road) - PRECISE COORDINATES 0-300 */}
                        <svg className="absolute inset-0 w-full h-full pointer-events-none z-0 overflow-visible" viewBox="0 0 300 300" preserveAspectRatio="none">
                             <defs>
                                <filter id="roadShadow" x="-20%" y="-20%" width="140%" height="140%">
                                    <feDropShadow dx="0" dy="4" stdDeviation="4" floodColor="#000000" floodOpacity="0.5"/>
                                </filter>
                            </defs>

                            {/* Base Road (Thick Asphalt) - 50 units wide */}
                            <path 
                                d="M 50 250 L 250 250 
                                   C 300 250 300 150 250 150
                                   L 50 150
                                   C 0 150 0 50 50 50
                                   L 250 50"
                                stroke="#475569" // Slate-600 (Dark Asphalt)
                                strokeWidth="50" 
                                fill="none" 
                                strokeLinecap="round"
                                strokeLinejoin="round"
                                filter="url(#roadShadow)"
                            />

                             {/* Road Border (Lighter Edge) */}
                             <path 
                                d="M 50 250 L 250 250 
                                   C 300 250 300 150 250 150
                                   L 50 150
                                   C 0 150 0 50 50 50
                                   L 250 50"
                                stroke="#64748b" // Slate-500
                                strokeWidth="44" 
                                fill="none" 
                                strokeLinecap="round"
                                strokeLinejoin="round"
                            />

                            {/* Road Markings (Yellow Dashed Line) */}
                             <path 
                                d="M 50 250 L 250 250 
                                   C 300 250 300 150 250 150
                                   L 50 150
                                   C 0 150 0 50 50 50
                                   L 250 50"
                                stroke="#facc15" // Yellow-400
                                strokeWidth="4" 
                                fill="none" 
                                strokeLinecap="round"
                                strokeLinejoin="round"
                                strokeDasharray="15 20"
                            />
                        </svg>

                        {/* Grid Nodes */}
                        <div className="w-full h-full grid grid-cols-3 grid-rows-3 gap-0 relative z-10">
                            {[7, 8, 9].map(lvl => <LevelNode key={lvl} level={lvl} players={players} levels={levels} />)}
                            {[6, 5, 4].map(lvl => <LevelNode key={lvl} level={lvl} players={players} levels={levels} />)}
                            {[1, 2, 3].map(lvl => <LevelNode key={lvl} level={lvl} players={players} levels={levels} />)}
                        </div>
                    </div>
                </div>

                {/* --- CONTROLS AREA --- */}
                <div className={`w-full lg:w-96 flex-shrink-0 p-4 sm:p-6 rounded-2xl border-2 overflow-y-auto max-h-[80vh] ${bgClass}`}>
                    <h2 className="text-xl font-bold mb-4 text-center border-b pb-2">Kontrol Guru</h2>
                    <p className="mb-4 text-sm text-center opacity-80">Klik kelompok untuk memberi tantangan.</p>

                    <div className="space-y-3">
                        {players.map((p, idx) => {
                            const isFinished = winner?.id === p.id; // Logic sederhana, jika ada winner, anggap game selesai
                            return (
                                <button 
                                    key={p.id}
                                    onClick={() => handleGroupClick(idx)}
                                    disabled={!!winner}
                                    className={`w-full flex items-center p-3 rounded-lg border-2 transition-transform hover:scale-105 ${isFinished ? 'bg-emerald-500 border-emerald-600' : 'bg-slate-700/50 border-transparent hover:border-yellow-400'}`}
                                >
                                    <div className={`w-8 h-8 rounded-full ${p.color} mr-3 border border-white`}></div>
                                    <div className="text-left flex-grow">
                                        <div className="font-bold text-white">{p.name}</div>
                                        <div className="text-xs text-slate-300">Level: {isFinished ? '🏆 SELESAI' : p.position}</div>
                                    </div>
                                    <div className="bg-white/20 px-3 py-1 rounded text-white font-bold text-sm">
                                        {isFinished ? 'Win' : 'Uji'}
                                    </div>
                                </button>
                            );
                        })}
                    </div>
                </div>
            </div>

            {/* Task Modal */}
            {modalTask && activeGroupIndex !== null && (
                <div className="fixed inset-0 bg-black/80 flex items-center justify-center p-4 z-50 backdrop-blur-sm">
                    <div className="bg-white w-full max-w-2xl rounded-2xl p-8 border-4 border-yellow-400 relative animate-content-fade">
                        <div className="absolute -top-6 -left-6 w-16 h-16 bg-yellow-400 rounded-full flex items-center justify-center border-4 border-white shadow-lg text-2xl font-bold text-yellow-900">
                            {modalTask.level}
                        </div>

                        <h2 className="text-center text-3xl font-bold font-caveat text-slate-800 mb-2">
                            Tantangan {players[activeGroupIndex].name}
                        </h2>
                        <div className="text-center mb-6">
                            <span className="bg-slate-200 text-slate-600 px-3 py-1 rounded-full text-sm font-bold uppercase tracking-wider">
                                Tingkat: {modalTask.difficulty}
                            </span>
                        </div>

                        <div className="bg-yellow-50 p-6 rounded-xl border-2 border-yellow-200 mb-8 min-h-[150px] flex items-center justify-center text-center overflow-y-auto max-h-[40vh]">
                            <p className="text-xl sm:text-2xl font-medium text-slate-800 whitespace-pre-wrap">{modalTask.content}</p>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <button 
                                onClick={() => handleValidation(false)}
                                className="bg-red-100 text-red-700 font-bold py-4 rounded-xl hover:bg-red-200 transition-colors border-2 border-red-200"
                            >
                                ❌ Belum
                                <span className="block text-xs font-normal opacity-70 mt-1">Tetap di Level {modalTask.level}</span>
                            </button>
                            <button 
                                onClick={() => handleValidation(true)}
                                className="bg-emerald-500 text-white font-bold py-4 rounded-xl hover:bg-emerald-600 transition-colors shadow-lg border-2 border-emerald-400 transform hover:scale-105"
                            >
                                {modalTask.level === 9 ? '🏆 JUARA!' : '✅ LULUS!'}
                                <span className="block text-xs font-normal opacity-90 mt-1">{modalTask.level === 9 ? 'Menangkan Game' : `Naik ke Level ${modalTask.level + 1}`}</span>
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

// --- SUB COMPONENT FOR NODE ---
const LevelNode: React.FC<{ level: number, players: Player[], levels: LevelContent }> = ({ level, players, levels }) => {
    const isBoss = level === 9;
    const playersHere = players.filter(p => p.position === level);

    return (
        <div className="relative flex items-center justify-center w-full h-full">
            {/* Circle Node */}
            <div 
                className={`w-16 h-16 sm:w-24 sm:h-24 rounded-full border-4 flex flex-col items-center justify-center shadow-xl z-10 transition-transform hover:scale-110
                    ${isBoss ? 'bg-gradient-to-br from-yellow-300 to-orange-400 border-white ring-4 ring-orange-500/50' : 'bg-stone-100 border-stone-400'}
                `}
            >
                <span className={`text-2xl sm:text-4xl font-bold font-caveat ${isBoss ? 'text-red-900 drop-shadow-sm' : 'text-slate-600'}`}>
                    {isBoss ? '👑' : level}
                </span>
                {isBoss && <span className="text-[10px] font-bold text-red-900 uppercase tracking-widest -mt-1">Puncak</span>}
            </div>

            {/* Players on this level */}
            <div className="absolute inset-0 pointer-events-none z-20 flex items-center justify-center">
                {playersHere.map((p, i) => (
                    <div 
                        key={p.id} 
                        className={`absolute transform transition-all duration-500 hover:z-30 hover:scale-125`}
                        style={{ 
                            // Spread players slightly so they don't overlap perfectly
                            transform: `translate(${i * 12 - (playersHere.length-1)*6}px, ${i * -8}px)` 
                        }}
                    >
                        <div className={`w-8 h-8 sm:w-10 sm:h-10 rounded-full border-2 border-white shadow-md ${p.color} flex items-center justify-center text-[10px] text-white font-bold`} title={p.name}>
                            {p.name.charAt(0)}
                        </div>
                    </div>
                ))}
            </div>

             {/* Difficulty Label (Optional, maybe too cluttered for mobile) */}
             {!isBoss && (
                 <div className="absolute bottom-2 text-[10px] text-slate-700 font-bold bg-white/90 px-2 py-0.5 rounded-full backdrop-blur-sm shadow-sm z-30 border border-slate-300">
                     {levels[level]?.difficulty}
                 </div>
             )}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { db } from '../firebase';
import { useAuth } from '../contexts/AuthContext';
import { collection, doc, addDoc, onSnapshot, updateDoc, deleteDoc, query, orderBy } from 'firebase/firestore';
import { ClassData, Student } from '../types';
import * as XLSX from 'xlsx';
import { Users, Upload, Plus, Trash2, X, Download } from 'lucide-react';

interface ClassManagerProps {
  onClose: () => void;
}

export const ClassManager: React.FC<ClassManagerProps> = ({ onClose }) => {
  const { user } = useAuth();
  const [classes, setClasses] = useState<ClassData[]>([]);
  const [selectedClass, setSelectedClass] = useState<ClassData | null>(null);
  const [newClassName, setNewClassName] = useState('');
  const [isAddingClass, setIsAddingClass] = useState(false);

  // Student Form
  const [newStudentName, setNewStudentName] = useState('');
  const [newStudentGender, setNewStudentGender] = useState<'L' | 'P'>('L');

  useEffect(() => {
    if (!user) return;
    const q = query(collection(db, 'users', user.uid, 'classes'), orderBy('name'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const classList = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as ClassData));
      setClasses(classList);
    });
    return unsubscribe;
  }, [user]);

  const handleAddClass = async () => {
    if (!newClassName.trim() || !user) return;
    await addDoc(collection(db, 'users', user.uid, 'classes'), {
      name: newClassName,
      students: [],
      createdAt: new Date()
    });
    setNewClassName('');
    setIsAddingClass(false);
  };

  const handleDeleteClass = async (classId: string) => {
    if (!user || !window.confirm('Hapus kelas ini? Data siswa akan hilang.')) return;
    await deleteDoc(doc(db, 'users', user.uid, 'classes', classId));
    if (selectedClass?.id === classId) setSelectedClass(null);
  };

  const handleAddStudent = async () => {
    if (!selectedClass || !user || !newStudentName.trim()) return;
    const newStudent: Student = {
      id: crypto.randomUUID(),
      name: newStudentName,
      gender: newStudentGender
    };
    const updatedStudents = [...selectedClass.students, newStudent];

    await updateDoc(doc(db, 'users', user.uid, 'classes', selectedClass.id), {
      students: updatedStudents
    });

    // Optimistic update for UI responsiveness
    setSelectedClass({ ...selectedClass, students: updatedStudents });
    setNewStudentName('');
  };

  const handleDeleteStudent = async (studentId: string) => {
    if (!selectedClass || !user) return;
    const updatedStudents = selectedClass.students.filter(s => s.id !== studentId);
    await updateDoc(doc(db, 'users', user.uid, 'classes', selectedClass.id), {
      students: updatedStudents
    });
    setSelectedClass({ ...selectedClass, students: updatedStudents });
  };

  const handleDownloadTemplate = () => {
    // Data contoh untuk template
    const templateData = [
      { "Nama": "Budi Santoso", "Jenis Kelamin": "L" },
      { "Nama": "Siti Aminah", "Jenis Kelamin": "P" },
      { "Nama": "Andi Pratama", "Jenis Kelamin": "L" },
      { "Nama": "Dewi Sartika", "Jenis Kelamin": "P" },
    ];

    const ws = XLSX.utils.json_to_sheet(templateData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Template Siswa");

    // Auto width columns (optional tweak)
    const wscols = [
        {wch: 30}, // Width for Name
        {wch: 15}, // Width for Gender
    ];
    ws['!cols'] = wscols;

    XLSX.writeFile(wb, "template_siswa_smartplay.xlsx");
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files || !e.target.files[0] || !selectedClass || !user) return;

    const file = e.target.files[0];
    const reader = new FileReader();

    reader.onload = async (evt) => {
      const bstr = evt.target?.result;
      const wb = XLSX.read(bstr, { type: 'binary' });
      const wsname = wb.SheetNames[0];
      const ws = wb.Sheets[wsname];
      const data = XLSX.utils.sheet_to_json(ws);

      const newStudents: Student[] = [];
      data.forEach((row: any) => {
        // Try to guess column names
        const name = row['Nama'] || row['nama'] || row['Name'] || row['Student Name'];
        let gender = row['Gender'] || row['L/P'] || row['Jenis Kelamin'] || row['Sex'];

        if (name) {
            // Normalize Gender
            if (typeof gender === 'string') {
                const g = gender.toUpperCase().trim();
                if (g.startsWith('L') || g === 'MALE' || g === 'PRIA') gender = 'L';
                else if (g.startsWith('P') || g === 'FEMALE' || g === 'WANITA') gender = 'P';
                else gender = 'L'; // Default fallback
            } else {
                gender = 'L';
            }

            newStudents.push({
                id: crypto.randomUUID(),
                name: String(name),
                gender: gender as 'L' | 'P'
            });
        }
      });

      if (newStudents.length > 0) {
          const updatedStudents = [...selectedClass.students, ...newStudents];
          await updateDoc(doc(db, 'users', user.uid, 'classes', selectedClass.id), {
              students: updatedStudents
          });
          setSelectedClass({ ...selectedClass, students: updatedStudents });
          alert(`Berhasil mengimpor ${newStudents.length} siswa!`);
      } else {
          alert("Tidak ditemukan data yang valid. Pastikan file Excel memiliki kolom 'Nama' dan 'Jenis Kelamin' (L/P).");
      }
      // Reset input file agar bisa upload file yang sama lagi jika perlu
      e.target.value = '';
    };
    reader.readAsBinaryString(file);
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-5xl h-[85vh] flex overflow-hidden border border-slate-200">

        {/* Sidebar: Class List */}
        <div className="w-1/3 bg-slate-50 border-r border-slate-200 flex flex-col">
          <div className="p-4 border-b border-slate-200 flex justify-between items-center bg-white">
            <h2 className="font-bold text-lg text-slate-700">Daftar Kelas</h2>
            <button onClick={() => setIsAddingClass(true)} className="bg-orange-100 text-orange-600 p-2 rounded-lg hover:bg-orange-200 transition-colors">
                <Plus size={20} />
            </button>
          </div>

          <div className="flex-grow overflow-y-auto p-2 space-y-2">
            {isAddingClass && (
                <div className="p-2 bg-white border border-orange-300 rounded-lg shadow-sm">
                    <input 
                        autoFocus
                        placeholder="Nama Kelas (e.g., 4A)" 
                        className="w-full p-2 border rounded mb-2 text-sm"
                        value={newClassName}
                        onChange={e => setNewClassName(e.target.value)}
                    />
                    <div className="flex gap-2">
                        <button onClick={handleAddClass} className="bg-orange-500 text-white px-3 py-1 rounded text-xs font-bold">Simpan</button>
                        <button onClick={() => setIsAddingClass(false)} className="bg-slate-200 text-slate-600 px-3 py-1 rounded text-xs">Batal</button>
                    </div>
                </div>
            )}

            {classes.map(cls => (
                <div 
                    key={cls.id}
                    onClick={() => setSelectedClass(cls)}
                    className={`p-3 rounded-lg cursor-pointer flex justify-between items-center group transition-all ${selectedClass?.id === cls.id ? 'bg-orange-500 text-white shadow-md' : 'bg-white hover:bg-slate-100 text-slate-700'}`}
                >
                    <div>
                        <div className="font-bold">{cls.name}</div>
                        <div className={`text-xs ${selectedClass?.id === cls.id ? 'text-orange-100' : 'text-slate-400'}`}>{cls.students.length} Siswa</div>
                    </div>
                    {selectedClass?.id !== cls.id && (
                        <button onClick={(e) => { e.stopPropagation(); handleDeleteClass(cls.id); }} className="text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity">
                            <Trash2 size={16} />
                        </button>
                    )}
                </div>
            ))}
            {classes.length === 0 && !isAddingClass && (
                <p className="text-center text-slate-400 text-sm mt-10">Belum ada kelas. Buat baru!</p>
            )}
          </div>
        </div>

        {/* Main Content: Student List */}
        <div className="w-2/3 flex flex-col bg-white">
