  const handleDownloadTemplate = () => {
    const templateData = [
      { "Nama": "Budi Santoso", "Jenis Kelamin": "L" },
      { "Nama": "Siti Aminah", "Jenis Kelamin": "P" },
    ];
    const ws = XLSX.utils.json_to_sheet(templateData);
    const wb = XLSX.utils.book_new();
