    XLSX.utils.book_append_sheet(wb, ws, "Template Siswa");
    const wscols = [{wch: 30}, {wch: 15}];
    ws['!cols'] = wscols;
    XLSX.writeFile(wb, "template_siswa_smartplay.xlsx");
  };

